13	
14	  // --- Base premiums for main items (single item, no modifiers, 1st-time customer with no prior contract) ---
15	  // For these isolated base-premium tests we expect: base + 10% first insurance + 5 fee, rounded up in MHPCO's favor.
16	  it.todo("quote for a single plain sword (steel, enchantment 3) → 100 G base premium drives the calculation");
17	  it.todo("quote for a single plain amulet → 60 G base premium drives the calculation");
18	  it.todo("quote for a single plain staff → 80 G base premium drives the calculation");
19	  it.todo("quote for a single plain potion → 40 G base premium drives the calculation");
20	
