22	  it.todo("2 runes → 50 G base premium (no block)");
23	  it.todo("3 runes → 60 G base premium (block applies)");
24	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
25	  it.todo("7 runes → 175 G base premium (no blocks formed; spec example)");
26	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
27	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
28	
29	  // --- Premium modifiers in isolation (newcomer scenarios anchor expected totals) ---
30	  it.todo("newcomer with a cursed sword (steel, enchantment 3) → premium 165 G (integration example)");
31	  it.todo("sword with enchantment 4 (not cursed) → no high-enchantment surcharge");
32	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
33	  it.todo("cursed sword with exactly enchantment 5 → both surcharges apply");
34	
35	  // --- Modifier scope on multi-item policies ---
36	  it.todo("cursed sword + plain amulet → base 160 G, +50 G curse surcharge on the sword only → 210 G before policy modifiers and fee");
37	
38	  // --- Loyalty / first insurance / follow-up modifiers ---
39	  it.todo("customer with exactly 2 years → loyalty discount applies");
40	  it.todo("long-standing customer's second contract: cursed sword enchantment 7 → premium 160 G (integration example; first insurance surcharge still applies per item)");
41	
42	  // --- Rounding in MHPCO's favor ---
43	  it.todo("a premium calculation that yields 197.5 G → final premium 198 G (rounded up)");
44	  it.todo("a payout calculation that yields 350.5 G → final payout 350 G (rounded down)");
45	
46	  // --- Claim processing: deductibles and standard reimbursement ---
47	  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G (full reimbursement minus 100 G deductible)");
48	  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G (full reimbursement minus 100 G deductible)");
49	  it.todo("dragon attack damages an insured sword (500 G) and amulet (300 G) → payout 600 G (100 G deductible per damaged item)");
50	
51	  // --- Claim processing: special clauses ---
52	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50 % rule wins, then deductible)");
53	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (only dragon-material clause applies)");
54	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (only high-enchantment clause applies)");
55	  it.todo("dragon-material sword with exactly enchantment 8, damage 1000 G → payout 400 G (high-enchantment clause applies first, then deductible)");
56	
57	  // --- Multiple items of same type and cap exhaustion ---
58	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G; dragon attack damages both → each entry treated as separate damage with its own deductible");
59	  it.todo("policy covers a sword and an amulet → insurance sum 1600 G, cap 3200 G");
60	  it.todo("cursed sword (insurance value 1000 G) → cap 2000 G (based on unmodified insurance value)");
61	  it.todo("policy covers a sword and 3 runes (block) → insurance sum 1750 G (block discount affects premium only, not insurance sum)");
62	  it.todo("sword insured (cap 2000 G); first claim 1500 G → payout 1400 G, remainingCap 600 G");
63	  it.todo("sword insured (cap 2000 G); after first 1500 G claim, second claim 1500 G → payout 600 G, remainingCap 0 G");
